  removeEscapeCharacter(string) {
    // http://www.endmemo.com/unicode/ascii.php
    return string
      ? string.trim().
        replace(/\r?\n/g, '<br/>').
        replace(/\\/g, '\\\\').
        replace(/"/g, '\\"').
        replace(/[\u0000-\u001F]/g, '')
      : ''
  },

  handleShowLineBreakTextarea(string) {
    return string
      ? string.replace(/\s?(<br\s?\/?>)\s?/g, '\r\n')
      : null
  },

  replaceHtmlEditor(htmlEditor) {
    //remove blank paragraph
    htmlEditor = htmlEditor.replace(/<p>&nbsp;<\/p>/gi, '')
    htmlEditor = htmlEditor.replace(/<p>\s*<\/p>/gi, '')
    //remove new line
    htmlEditor = htmlEditor.replace(/(?:\r\n|\r|\n)/g, '')
    return htmlEditor
  },

  removeDuplicateBrTags(content) {
    return content
      ? content.replace(/(<br *\/?>[\s|&nbsp;]*)+/gi, '<br>').
        replace(/(<p><br>[\s|&nbsp;]*<\/p>)+/gi, '<p><br></p>')
      : null
  },

  generateSlug(string) {
    const stringWithoutAccent = this.removeAccentedCharacter(string)

    if (!stringWithoutAccent) {
      return null
    }

    const stringWithoutSpecialCharacter = stringWithoutAccent.replace(
      /[^A-Za-z0-9 &]+/g, '')

    return slugify(stringWithoutSpecialCharacter, { lower: true })
  },

