  getDomainFromUrl(url) {
    const domainRegex = /(?:[\w-]+\.)+[\w-]+/

    const urlDomain = domainRegex.exec(url)
    if (!urlDomain || urlDomain.length === 0) {
      return null
    }
    return urlDomain[0]
  },

  checkDeniedHost(url) {
    return hostBlackList.some((hostname) => hostname === url)
  },

  //#Source https://bit.ly/2neWfJ2
  pluralize(val, word, plural = word + 's') {
    const _pluralize = (num, word, plural = word + 's') =>
      [1, -1].includes(Number(num)) ? word : plural
    if (typeof val === 'object') return (num, word) => _pluralize(num, word,
      val[word])
    return _pluralize(val, word, plural)
  }
